/* BTDrawer — multi-side sliding panel with overlay.
   Figma D-Drawer: 2616:12959 (web) · M-Drawer: 2616:13119 (mobile).
   Shared between @btech/ui-vue and @btech/ui-react — keep these files identical.

   side = right  → 400 px wide, full height, slides from right
   side = left   → 400 px wide, full height, slides from left
   side = bottom → full width, ≤50 vh, slides from bottom
   side = top    → full width, ≤50 vh, slides from top
*/

/* ── Backdrop / overlay ──────────────────────────────────────────────────── */

.bt-drawer-backdrop {
  position: fixed;
  inset: 0;
  /* Raw rgba allowed (CLAUDE.md §6) — opacity overlay, not a named token. */
  background: rgba(0, 0, 0, 0.5);
  z-index: 9000;
  display: flex;
}

/* Side-specific backdrop layout — positions the panel */
.bt-drawer-backdrop--right  { flex-direction: row;    align-items: stretch;  justify-content: flex-end;   }
.bt-drawer-backdrop--left   { flex-direction: row;    align-items: stretch;  justify-content: flex-start; }
.bt-drawer-backdrop--bottom { flex-direction: column; align-items: stretch;  justify-content: flex-end;   }
.bt-drawer-backdrop--top    { flex-direction: column; align-items: stretch;  justify-content: flex-start; }

/* ── Panel — shared base ─────────────────────────────────────────────────── */

.bt-drawer-panel {
  position: relative;
  display: flex;
  flex-direction: column;
  background: var(--bg-primary);
  overflow: hidden;
  font-family: var(--typography-font-family-sans);
  color: var(--text-primary);
}

/* Side-specific panel shape + shadow */
.bt-drawer-panel--right {
  width: 400px;
  height: 100%;
  max-height: 100vh;
  box-shadow: -4px 0 24px rgba(0, 0, 0, 0.15);
}

.bt-drawer-panel--left {
  width: 400px;
  height: 100%;
  max-height: 100vh;
  box-shadow: 4px 0 24px rgba(0, 0, 0, 0.15);
}

.bt-drawer-panel--bottom {
  width: 100%;
  max-height: 50vh;
  box-shadow: 0 -8px 12px rgba(0, 0, 0, 0.15);
}

.bt-drawer-panel--top {
  width: 100%;
  max-height: 50vh;
  box-shadow: 0 8px 12px rgba(0, 0, 0, 0.15);
}

/* ── Header ──────────────────────────────────────────────────────────────── */

.bt-drawer-header {
  display: flex;
  flex-direction: row;
  align-items: flex-start;
  gap: var(--space-md);
  padding: 24px 24px 16px;
  flex-shrink: 0;
  background: var(--bg-primary);
  border-bottom: 1px solid var(--border-primary);
}

.bt-drawer-header__text {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-drawer-title {
  font-size: var(--typography-font-size-lg);
  font-weight: 700;
  line-height: 1.4;
  color: var(--text-primary);
  margin: 0;
}

.bt-drawer-subtext {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: 1.4;
  color: var(--text-secondary);
  margin: 0;
}

.bt-drawer-close {
  flex-shrink: 0;
  width: 24px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  background: transparent;
  color: var(--text-secondary);
  cursor: pointer;
  border-radius: var(--radius-xs);
  padding: 0;
  transition: background 0.12s ease, color 0.12s ease;
}

.bt-drawer-close:hover {
  background: var(--bg-subtle);
  color: var(--text-primary);
}

.bt-drawer-close:focus-visible {
  outline: 2px solid var(--color-brand-primary);
  outline-offset: 1px;
}

/* ── Body content (flexible + scrollable) ────────────────────────────────── */

.bt-drawer-content {
  flex: 1;
  min-height: 0;       /* required for flex children to scroll */
  padding: var(--space-lg) 24px;
  overflow-y: auto;
  background: var(--bg-primary);
}

/* ── Footer ──────────────────────────────────────────────────────────────── */

.bt-drawer-footer {
  display: flex;
  flex-direction: row;   /* horizontal default: secondary LEFT, primary RIGHT */
  gap: var(--space-sm);
  padding: var(--space-lg) 24px 24px;
  flex-shrink: 0;
  background: var(--bg-primary);
  border-top: 1px solid var(--border-primary);
}

.bt-drawer-footer--vertical {
  flex-direction: column;  /* primary TOP, secondary BOTTOM */
}

.bt-drawer-footer > * {
  flex: 1;  /* equal-width buttons in both directions */
}

/* ── Animations (Vue <Transition name="bt-drawer">) ──────────────────────── */

.bt-drawer-enter-active { transition: opacity 0.2s ease; }
.bt-drawer-leave-active { transition: opacity 0.15s ease; }
.bt-drawer-enter-from,
.bt-drawer-leave-to { opacity: 0; }

.bt-drawer-enter-active .bt-drawer-panel {
  transition: opacity 0.2s ease, transform 0.2s ease;
}
.bt-drawer-leave-active .bt-drawer-panel {
  transition: opacity 0.15s ease, transform 0.15s ease;
}

/* Per-side slide-in origins for Vue Transition */
.bt-drawer-enter-from .bt-drawer-panel--right,
.bt-drawer-leave-to   .bt-drawer-panel--right  { opacity: 0; transform: translateX(100%); }

.bt-drawer-enter-from .bt-drawer-panel--left,
.bt-drawer-leave-to   .bt-drawer-panel--left   { opacity: 0; transform: translateX(-100%); }

.bt-drawer-enter-from .bt-drawer-panel--bottom,
.bt-drawer-leave-to   .bt-drawer-panel--bottom { opacity: 0; transform: translateY(100%); }

.bt-drawer-enter-from .bt-drawer-panel--top,
.bt-drawer-leave-to   .bt-drawer-panel--top    { opacity: 0; transform: translateY(-100%); }

/* ── Animations (React — @keyframes + --animated class) ─────────────────── */

@keyframes bt-drawer-backdrop-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes bt-drawer-panel-in-right  { from { opacity: 0; transform: translateX(100%); }  to { opacity: 1; transform: none; } }
@keyframes bt-drawer-panel-in-left   { from { opacity: 0; transform: translateX(-100%); } to { opacity: 1; transform: none; } }
@keyframes bt-drawer-panel-in-bottom { from { opacity: 0; transform: translateY(100%); }  to { opacity: 1; transform: none; } }
@keyframes bt-drawer-panel-in-top    { from { opacity: 0; transform: translateY(-100%); } to { opacity: 1; transform: none; } }

.bt-drawer-backdrop--animated {
  animation: bt-drawer-backdrop-in 0.2s ease forwards;
}

.bt-drawer-backdrop--animated .bt-drawer-panel--right  { animation: bt-drawer-panel-in-right  0.2s ease forwards; }
.bt-drawer-backdrop--animated .bt-drawer-panel--left   { animation: bt-drawer-panel-in-left   0.2s ease forwards; }
.bt-drawer-backdrop--animated .bt-drawer-panel--bottom { animation: bt-drawer-panel-in-bottom 0.2s ease forwards; }
.bt-drawer-backdrop--animated .bt-drawer-panel--top    { animation: bt-drawer-panel-in-top    0.2s ease forwards; }

/**
 * BTDrawer — multi-side sliding panel with overlay, header, body, optional footer.
 *
 * Figma: D-Drawer 2616:12959 (web) · M-Drawer 2616:13119 (mobile).
 *
 * @example
 * ```tsx
 * import { useState } from 'react';
 * import { BTDrawer } from '@btech/ui-react';
 *
 * export function Example() {
 *   const [open, setOpen] = useState(false);
 *   return (
 *     <>
 *       <button onClick={() => setOpen(true)}>Open</button>
 *       <BTDrawer
 *         open={open}
 *         side="right"
 *         title="Settings"
 *         onPrimary={() => setOpen(false)}
 *         onClose={() => setOpen(false)}
 *       >
 *         <p>Drawer body content.</p>
 *       </BTDrawer>
 *     </>
 *   );
 * }
 * ```
 */
import { useEffect, type ReactNode } from 'react';
import { createPortal } from 'react-dom';
import './BTDrawer.css';
import type { BTDrawerProps } from './BTDrawer.types';
import { BTButton } from '../button/BTButton';

interface BTDrawerReactProps extends BTDrawerProps {
  children?: ReactNode;
  onPrimary?: () => void;
  onSecondary?: () => void;
  onClose?: () => void;
}

export function BTDrawer({
  open,
  side = 'right',
  title,
  subtext,
  hasCloseIcon = true,
  hasFooter = true,
  primaryLabel = 'Confirm',
  hasSecondaryButton = true,
  secondaryLabel = 'Cancel',
  dismissable = true,
  buttonDirection = 'horizontal',
  children,
  onPrimary,
  onSecondary,
  onClose,
}: BTDrawerReactProps) {
  // ── Body scroll lock ───────────────────────────────────────────────────────
  useEffect(() => {
    if (typeof document === 'undefined') return;
    if (open) {
      const prev = document.body.style.overflow;
      document.body.style.overflow = 'hidden';
      return () => { document.body.style.overflow = prev; };
    }
    return undefined;
  }, [open]);

  if (!open) return null;
  if (typeof document === 'undefined') return null;

  function close(): void { onClose?.(); }

  function handleBackdropClick(e: React.MouseEvent<HTMLDivElement>): void {
    if (e.target !== e.currentTarget) return;
    if (dismissable) close();
  }

  return createPortal(
    <div
      className={`bt-drawer-backdrop bt-drawer-backdrop--${side} bt-drawer-backdrop--animated`}
      onClick={handleBackdropClick}
    >
      <div
        className={`bt-drawer-panel bt-drawer-panel--${side}`}
        role="dialog"
        aria-modal="true"
        aria-label={title}
      >
        {/* Header */}
        <div className="bt-drawer-header">
          <div className="bt-drawer-header__text">
            {title && <h2 className="bt-drawer-title">{title}</h2>}
            {subtext && <p className="bt-drawer-subtext">{subtext}</p>}
          </div>
          {hasCloseIcon && (
            <button
              type="button"
              className="bt-drawer-close"
              aria-label="Close"
              onClick={close}
            >
              <svg width="16" height="16" viewBox="0 0 16 16" aria-hidden="true">
                <path
                  d="M3.5 3.5 L12.5 12.5 M12.5 3.5 L3.5 12.5"
                  stroke="currentColor"
                  strokeWidth="1.6"
                  strokeLinecap="round"
                />
              </svg>
            </button>
          )}
        </div>

        {/* Body (scrollable) */}
        {children && <div className="bt-drawer-content">{children}</div>}

        {/* Footer */}
        {hasFooter && (
          <div className={[
            'bt-drawer-footer',
            buttonDirection === 'vertical' ? 'bt-drawer-footer--vertical' : '',
          ].filter(Boolean).join(' ')}>
            {/* Horizontal (default): secondary LEFT, primary RIGHT */}
            {buttonDirection !== 'vertical' ? (
              <>
                {hasSecondaryButton && (
                  <BTButton
                    variant="secondary-light"
                    label={secondaryLabel}
                    onClick={() => onSecondary?.()}
                  />
                )}
                <BTButton
                  label={primaryLabel}
                  onClick={() => onPrimary?.()}
                />
              </>
            ) : (
              /* Vertical: primary TOP, secondary BOTTOM */
              <>
                <BTButton
                  label={primaryLabel}
                  onClick={() => onPrimary?.()}
                />
                {hasSecondaryButton && (
                  <BTButton
                    variant="secondary-light"
                    label={secondaryLabel}
                    onClick={() => onSecondary?.()}
                  />
                )}
              </>
            )}
          </div>
        )}
      </div>
    </div>,
    document.body,
  );
}
BTDrawer.displayName = 'BTDrawer';

export type BTDrawerSide = 'top' | 'right' | 'bottom' | 'left';
export type BTDrawerButtonDirection = 'horizontal' | 'vertical';

export interface BTDrawerProps {
  open: boolean;
  /** Which edge the panel slides in from. @default 'right' */
  side?: BTDrawerSide;
  title?: string;
  subtext?: string;
  hasCloseIcon?: boolean;
  hasFooter?: boolean;
  primaryLabel?: string;
  hasSecondaryButton?: boolean;
  secondaryLabel?: string;
  dismissable?: boolean;
  /** Footer button layout direction. @default 'horizontal' */
  buttonDirection?: BTDrawerButtonDirection;
}
